import ExpenseItem from './Components/ExpenseItem';

function App() {
  let item_list = {
    item1:{
      date: "24-05-2021",
      title: "Sleepwell bed",
      amount: 12000
    },
    item2:{
      date: "20-05-2021",
      title: "Real Juice",
      amount: 349
    },
    item3:{
      date: "22-05-2021",
      title: "Antidandruff shampoo",
      amount: 450
    }
  }
  return (
    <div className="App">
      <h2>Let's get started!</h2>
      <ExpenseItem date = {item_list.item1.date} title = {item_list.item1.title} amount = {item_list.item1.amount}></ExpenseItem>
      <ExpenseItem date = {item_list.item2.date} title = {item_list.item2.title} amount = {item_list.item2.amount}></ExpenseItem>
      <ExpenseItem date = {item_list.item3.date} title = {item_list.item3.title} amount = {item_list.item3.amount}></ExpenseItem>
    </div>
  );
}

export default App;
